import math
from dataclasses import dataclass

@dataclass
class DetectionEvaluation:
    threshold: float       # score cutoff above which text is classified as AI
    tp: int                # true positives (AI correctly flagged)
    fp: int                # false positives (human incorrectly flagged)
    fn: int                # false negatives (AI missed)
    tn: int                # true negatives (human correctly passed)

    @property
    def tpr(self) -> float:
        return self.tp / (self.tp + self.fn) if (self.tp + self.fn) > 0 else 0.0

    @property
    def fpr(self) -> float:
        return self.fp / (self.fp + self.tn) if (self.fp + self.tn) > 0 else 0.0

    @property
    def precision(self) -> float:
        return self.tp / (self.tp + self.fp) if (self.tp + self.fp) > 0 else 0.0

    @property
    def f1(self) -> float:
        p, r = self.precision, self.tpr
        return 2 * p * r / (p + r) if (p + r) > 0 else 0.0

    def summary(self) -> str:
        return (
            f"threshold={self.threshold:.2f}  "
            f"TPR={self.tpr:.3f}  FPR={self.fpr:.4f}  "
            f"Precision={self.precision:.3f}  F1={self.f1:.3f}"
        )


def evaluate_at_thresholds(
    scores: list[float],    # P(AI) for each sample
    labels: list[int],      # ground truth: 1=AI, 0=human
    thresholds: list[float] | None = None,
) -> list[DetectionEvaluation]:
    """Compute evaluation metrics across a range of thresholds."""
    if thresholds is None:
        thresholds = [i / 100 for i in range(0, 101, 5)]
    results = []
    for thresh in thresholds:
        preds = [1 if s >= thresh else 0 for s in scores]
        tp = sum(p == 1 and l == 1 for p, l in zip(preds, labels))
        fp = sum(p == 1 and l == 0 for p, l in zip(preds, labels))
        fn = sum(p == 0 and l == 1 for p, l in zip(preds, labels))
        tn = sum(p == 0 and l == 0 for p, l in zip(preds, labels))
        results.append(DetectionEvaluation(thresh, tp, fp, fn, tn))
    return results

