from typing import Callable

DetectorFn = Callable[[str], float]   # text -> P(AI-generated)

def adversarial_robustness_suite(
    ai_texts: list[str],
    detector: DetectorFn,
    paraphrase_fn: Callable[[str], str] | None = None,
    detection_threshold: float = 0.8,
) -> dict[str, float]:
    """
    Run the detector against common evasion attacks.
    Returns the evasion rate (fraction of AI texts that escape detection)
    for each attack type.
    """
    def evasion_rate(texts: list[str]) -> float:
        scores = [detector(t) for t in texts]
        evaded = sum(s < detection_threshold for s in scores)
        return evaded / len(texts) if texts else 0.0

    import random, re

    def random_synonym_substitute(text: str, p: float = 0.15) -> str:
        """Replace ~p fraction of words with a random synonym (naive stand-in)."""
        replacements = {"quick": "rapid", "large": "big", "use": "employ",
                        "help": "assist", "make": "create", "get": "obtain"}
        words = text.split()
        return " ".join(
            replacements.get(w.lower(), w) if random.random() < p else w
            for w in words
        )

    def add_typos(text: str, p: float = 0.03) -> str:
        """Introduce random character transpositions."""
        chars = list(text)
        for i in range(len(chars) - 1):
            if random.random() < p and chars[i].isalpha() and chars[i+1].isalpha():
                chars[i], chars[i+1] = chars[i+1], chars[i]
        return "".join(chars)

    results: dict[str, float] = {
        "baseline": evasion_rate(ai_texts),
        "synonym_substitution_15pct": evasion_rate([
            random_synonym_substitute(t, 0.15) for t in ai_texts
        ]),
        "typos_3pct": evasion_rate([add_typos(t) for t in ai_texts]),
        "truncation_50pct": evasion_rate([
            t[:len(t)//2] for t in ai_texts if len(t) > 100
        ]),
    }
    if paraphrase_fn is not None:
        results["paraphrase"] = evasion_rate([
            paraphrase_fn(t) for t in ai_texts
        ])
    return results

# A well-engineered detector should maintain evasion_rate < 0.2 on
# synonym substitution. Paraphrase evasion rates of 0.6–0.9 are typical
# for token-level classifiers — this is the main open problem in the field.
